#include <iostream>
#include <sstream>
#include <vector>

using namespace std;

struct Node {
    int val;
    Node* prev;
    Node* next;
};

class Solution {
public:
    void read(istream& in, Node*& head) {
        int n;
        in >> n;
        vector<int> nodes(n);
        in.read((char*)&nodes[0], n * 4);
        head = new Node(nodes[0]);
        Node* curr = head;
        for (int i = 1; i < n; ++i) {
            curr->next = new Node(nodes[i]);
            curr->next->prev = curr;
            curr = curr->next;
        }
    }

    void merge(Node* l1, Node* l2, Node*& head) {
        Node dummy(0);
        Node* curr = &dummy;
        while (l1 && l2) {
            if (l1->val < l2->val) {
                curr->next = l1;
                l1->prev = curr;
                curr = curr->next;
                l1 = l1->next;
            } else {
                curr->next = l2;
                l2->prev = curr;
                curr = curr->next;
                l2 = l2->next;
            }
        }
        if (l1) {
            curr->next = l1;
            l1->prev = curr;
        } else {
            curr->next = l2;
        }
        while (curr->next) {
            curr = curr->next;
        }
        head = dummy.next;
    }

    void print(Node* head) {
        while (head) {
            cout << head->val << ' ';
            head = head->next;
        }
        cout << endl;
    }
};

